 using Microsoft.ML;
 using Microsoft.ML.Data;
 using Microsoft.Extensions.ML;
 using ChurnPredictor.Models;

 var builder = WebApplication.CreateBuilder(args);

 // Train the model at startup and register the pooled prediction engine
 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");

 TrainAndSaveModel(mlContext, dataPath, modelPath);

 builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
 {
     var input = new CustomerData
     {
         Age = req.Age,
         Income = req.Income,
         Region = req.Region,
         PurchaseHistory = req.PurchaseHistory
     };

     var prediction = pool.Predict(input);
     return Results.Ok(new
     {
         willChurn = prediction.PredictedLabel,
         confidence = prediction.Probability
     });
 });

 app.Run();

 static void TrainAndSaveModel(MLContext mlContext, string dataPath, string modelPath)
 {
     var data = mlContext.Data.LoadFromTextFile<CustomerData>(
         dataPath, hasHeader: true, separatorChar: ',');

     var rowCount = (int)data.GetColumn<float>(nameof(CustomerData.Age)).LongCount();

     mlContext.ComponentCatalog.RegisterAssembly(typeof(ChurnLabelMappingFactory).Assembly);

     var pipeline = mlContext.Transforms.CustomMapping<CustomerData, ChurnLabelMapping>(
             new ChurnLabelMappingFactory().GetMapping(),
             contractName: ChurnLabelMappingFactory.ContractName)
         .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
         .Append(mlContext.Transforms.Concatenate("Features",
             nameof(CustomerData.Age),
             nameof(CustomerData.Income),
             nameof(CustomerData.PurchaseHistory),
             "RegionEncoded"))
         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
         .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
             labelColumnName: "Label", featureColumnName: "Features"));

     ITransformer model;

     // Need enough rows with both classes for a meaningful train/test split
     if (rowCount >= 20)
     {
         var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
         model = pipeline.Fit(split.TrainSet);

         var predictions = model.Transform(split.TestSet);
         var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

         Console.WriteLine("=== Churn Model Evaluation ===");
         Console.WriteLine($"  AUC:      {metrics.AreaUnderRocCurve:F4}");
         Console.WriteLine($"  F1 Score: {metrics.F1Score:F4}");
         Console.WriteLine($"  Accuracy: {metrics.Accuracy:F4}");
     }
     else
     {
         Console.WriteLine($"WARNING: Only {rowCount} rows — training on all data (no evaluation split).");
         Console.WriteLine("Add more rows to Data/customers.csv for meaningful evaluation metrics.");
         model = pipeline.Fit(data);
     }

     mlContext.Model.Save(model, data.Schema, modelPath);
     Console.WriteLine($"Model saved to {modelPath}");
 }

